from pathlib import Path
import urllib.request, json, re
import numpy as np
import pandas as pd

RESULT_DIR = Path("/content/drive/MyDrive/result_split7")
PROJECT_DIR = Path("/content/drive/MyDrive/PhD_protein_design/6mrr_modular_design_20260623_fixed6MRR_MPNNsweep_AFcheck")
TARGET_PDB_ID = "6MRR"
TARGET_CHAIN = "A"
MPNN_CSV = PROJECT_DIR / "data/6MRR_chain_A__MPNN_temperature_sweep__all_candidates_summary.csv"

OUT_REF_PDB = RESULT_DIR / "6MRR_chain_A_deduplicated_reference.pdb"
OUT_TABLE = RESULT_DIR / "FINAL_6MRR_design_validation_table_v3_dedup_reference.csv"
OUT_AUDIT = RESULT_DIR / "RMSD_REFERENCE_AUDIT_v3_dedup_reference.md"

try:
    from google.colab import drive
    drive.mount("/content/drive")
except Exception as e:
    print("Drive mount skipped:", e)

if not RESULT_DIR.exists():
    raise FileNotFoundError(f"Missing RESULT_DIR: {RESULT_DIR}")

target_pdb = RESULT_DIR / f"{TARGET_PDB_ID}.pdb"
if not target_pdb.exists():
    urllib.request.urlretrieve(f"https://files.rcsb.org/download/{TARGET_PDB_ID}.pdb", target_pdb)

def atom_key(line):
    return (line[21].strip(), line[22:26].strip(), line[26].strip(), line[12:16].strip())

def altloc(line):
    return line[16].strip()

def occupancy(line):
    try:
        return float(line[54:60])
    except Exception:
        return 0.0

def atom_choice_score(line):
    a = altloc(line)
    pref = 3 if a == "" else 2 if a == "A" else 1
    return (pref, occupancy(line))

# Build deduplicated reference: one atom per chain/residue/insertion/atom-name.
chosen = {}
with open(target_pdb, "r", errors="ignore") as f:
    for line in f:
        if not line.startswith("ATOM"):
            continue
        if line[21].strip() != TARGET_CHAIN:
            continue
        k = atom_key(line)
        if k not in chosen or atom_choice_score(line) > atom_choice_score(chosen[k]):
            chosen[k] = line[:16] + " " + line[17:]

def sort_key(item):
    k, line = item
    chain, resseq, icode, atom = k
    try:
        resnum = int(resseq)
    except Exception:
        resnum = 999999
    atom_order = {"N":0, "CA":1, "C":2, "O":3}.get(atom, 99)
    return (resnum, icode, atom_order, atom)

with open(OUT_REF_PDB, "w") as out:
    for i, (k, line) in enumerate(sorted(chosen.items(), key=sort_key), start=1):
        out.write(f"{line[:6]}{i:5d}{line[11:]}")
    out.write("END\n")

def parse_ca_coords(pdb_path, chain_id=None, unique_residue=True):
    coords, labels, b = [], [], []
    seen = set()
    with open(pdb_path, "r", errors="ignore") as f:
        for line in f:
            if not line.startswith("ATOM"):
                continue
            if line[12:16].strip() != "CA":
                continue
            ch = line[21].strip()
            if chain_id is not None and ch != chain_id:
                continue
            key = (ch, line[22:26].strip(), line[26].strip())
            if unique_residue and key in seen:
                continue
            seen.add(key)
            coords.append([float(line[30:38]), float(line[38:46]), float(line[46:54])])
            labels.append((line[17:20].strip(), line[22:26].strip(), line[26].strip()))
            try:
                b.append(float(line[60:66]))
            except Exception:
                b.append(np.nan)
    return np.array(coords, float), labels, np.array(b, float)

def kabsch_rmsd(P, Q):
    Pc, Qc = P - P.mean(axis=0), Q - Q.mean(axis=0)
    V, S, Wt = np.linalg.svd(Pc.T @ Qc)
    d = np.sign(np.linalg.det(V @ Wt))
    U = V @ np.diag([1,1,d]) @ Wt
    return float(np.sqrt((((Pc @ U) - Qc) ** 2).sum() / len(P)))

def extract_design_id(path):
    for s in [path.name, path.parent.name]:
        m = re.search(r"(\d{2}_6MRR_chain_A__T\d+p\d+__sample\d+)", s)
        if m:
            return m.group(1)
    return path.stem

def compact_id(x):
    m = re.search(r"(T\d+p\d+__sample\d+)", x)
    return m.group(1) if m else x

def parse_temp_sample(x):
    t, sample = np.nan, np.nan
    m = re.search(r"T(\d+)p(\d+)", x)
    if m:
        t = float(f"{m.group(1)}.{m.group(2)}")
    m = re.search(r"sample(\d+)", x)
    if m:
        sample = int(m.group(1))
    return t, sample

def rank_num(p):
    m = re.search(r"rank_(\d+)", p.name)
    if m:
        return int(m.group(1))
    m = re.search(r"ranked_(\d+)", p.name)
    if m:
        return int(m.group(1)) + 1
    return 999

def find_score_json_for_pdb(pdb_path):
    model = re.search(r"(alphafold2_ptm_model_\d+_seed_\d+)", pdb_path.name)
    model_key = model.group(1) if model else ""
    design_id = extract_design_id(pdb_path)
    short = compact_id(design_id)
    best, best_score = None, -1
    for j in RESULT_DIR.rglob("*.json"):
        s, score = str(j), 0
        if design_id in s or short in s:
            score += 2
        if model_key and model_key in s:
            score += 3
        if "rank_001" in s:
            score += 2
        if "score" in s:
            score += 1
        if score > best_score:
            best, best_score = j, score
    return best

def parse_scores(j):
    out = {"mean_plddt":np.nan, "ptm":np.nan, "mean_pae":np.nan}
    if j is None or not j.exists():
        return out
    try:
        data = json.load(open(j))
    except Exception:
        return out
    if "plddt" in data:
        out["mean_plddt"] = float(np.mean(data["plddt"]))
    elif "mean_plddt" in data:
        out["mean_plddt"] = float(data["mean_plddt"])
    if "ptm" in data:
        out["ptm"] = float(data["ptm"])
    elif "pTM" in data:
        out["ptm"] = float(data["pTM"])
    for key in ["pae", "predicted_aligned_error"]:
        if key in data:
            out["mean_pae"] = float(np.nanmean(np.array(data[key], dtype=float)))
            break
    return out

mpnn_df = pd.read_csv(MPNN_CSV) if MPNN_CSV.exists() else None
fallback_reason = {
    "T0p1__sample10": "lowest_mpnn_score_at_this_temperature",
    "T0p3__sample05": "lowest_mpnn_score_at_this_temperature",
    "T0p3__sample08": "highest_seq_recovery_at_this_temperature",
    "T0p5__sample01": "lowest_mpnn_score_at_this_temperature",
    "T0p5__sample10": "highest_seq_recovery_at_this_temperature",
    "T1p0__sample01": "highest_seq_recovery_at_this_temperature",
    "T1p0__sample10": "lowest_mpnn_score_at_this_temperature",
}
def lookup_mpnn(design_id):
    out = {"mpnn_score":np.nan, "seq_recovery":np.nan, "selection_reason":fallback_reason.get(compact_id(design_id), "")}
    if mpnn_df is None:
        return out
    no_prefix = re.sub(r"^\d{2}_", "", design_id)
    for col in ["design_id", "candidate_id", "name", "id"]:
        if col in mpnn_df.columns:
            hit = mpnn_df[mpnn_df[col].astype(str).str.contains(no_prefix, regex=False, na=False)]
            if len(hit):
                row = hit.iloc[0]
                for k in out:
                    if k in row.index:
                        out[k] = row[k]
                return out
    return out

def best_window_rmsd(pred, ref_coords, ref_labels):
    n = len(pred)
    best_r, best_i = np.inf, None
    for i in range(0, len(ref_coords)-n+1):
        r = kabsch_rmsd(pred, ref_coords[i:i+n])
        if r < best_r:
            best_r, best_i = r, i
    start, end = best_i, best_i + n
    s, e = ref_labels[start], ref_labels[end-1]
    return best_r, f"{s[0]}{s[1]}{s[2]}{s[3]}-{e[0]}{e[1]}{e[2]}{e[3]}", f"{start+1}-{end}"

def classify(r, plddt):
    if r < 2 and plddt >= 80:
        return "PASS_STRONG"
    if r < 3 and plddt >= 70:
        return "PASS_ACCEPTABLE"
    if r < 5 and plddt >= 70:
        return "BORDERLINE"
    return "FAIL"

# Compare raw CA count vs unique/deduplicated count.
raw_all_ca, raw_all_labels, _ = parse_ca_coords(target_pdb, TARGET_CHAIN, unique_residue=False)
raw_unique_ca, raw_unique_labels, _ = parse_ca_coords(target_pdb, TARGET_CHAIN, unique_residue=True)
ref_coords, ref_labels, _ = parse_ca_coords(OUT_REF_PDB, TARGET_CHAIN, unique_residue=True)

print("Raw CA atom records in downloaded target:", len(raw_all_ca))
print("Unique-residue CA count in downloaded target:", len(raw_unique_ca))
print("Deduplicated reference CA count:", len(ref_coords))
print("Deduplicated reference first-last:", ref_labels[0], ref_labels[-1])

pred_pdbs = [p for p in RESULT_DIR.rglob("*.pdb") if p != target_pdb and ("rank_" in p.name or "ranked_" in p.name)]
groups = {}
for p in pred_pdbs:
    groups.setdefault(extract_design_id(p), []).append(p)

rows = []
for design_id, pdbs in sorted(groups.items()):
    rank1 = sorted(pdbs, key=rank_num)[0]
    pred_coords, _, pred_b = parse_ca_coords(rank1, None, unique_residue=True)
    scores = parse_scores(find_score_json_for_pdb(rank1))
    mean_plddt = scores["mean_plddt"] if not np.isnan(scores["mean_plddt"]) else float(np.nanmean(pred_b))
    temp, sample = parse_temp_sample(design_id)
    mpnn = lookup_mpnn(design_id)

    if len(ref_coords) == len(pred_coords):
        rmsd = kabsch_rmsd(pred_coords, ref_coords)
        mode = "deduplicated_chain_A_exact_length"
        window_label = "full_deduplicated_chain_A"
        window_index = "full_deduplicated_chain_A"
    else:
        rmsd, window_label, window_index = best_window_rmsd(pred_coords, ref_coords, ref_labels)
        mode = "best_window_of_deduplicated_chain_A"

    rows.append({
        "priority_order": np.nan,
        "design_id": design_id,
        "short_id": compact_id(design_id),
        "temperature": temp,
        "sample": sample,
        "selection_reason": mpnn["selection_reason"],
        "dedup_reference_rmsd_A": rmsd,
        "mean_plddt": mean_plddt,
        "ptm": scores["ptm"],
        "mean_pae": scores["mean_pae"],
        "mpnn_score": mpnn["mpnn_score"],
        "seq_recovery": mpnn["seq_recovery"],
        "self_consistency_status": classify(rmsd, mean_plddt),
        "reference_mode": mode,
        "target_window_label": window_label,
        "target_window_index": window_index,
        "n_ca_raw_atom_records": len(raw_all_ca),
        "n_ca_unique_reference": len(ref_coords),
        "n_ca_pred": len(pred_coords),
        "rank1_pdb": str(rank1),
    })

df = pd.DataFrame(rows)
rank_map = {"PASS_STRONG":0, "PASS_ACCEPTABLE":1, "BORDERLINE":2, "FAIL":3}
df["_r"] = df["self_consistency_status"].map(rank_map).fillna(9)
df = df.sort_values(["_r", "dedup_reference_rmsd_A", "mean_plddt"], ascending=[True, True, False]).drop(columns="_r").reset_index(drop=True)
df["priority_order"] = range(1, len(df)+1)

for c in ["dedup_reference_rmsd_A","mean_plddt","ptm","mean_pae","mpnn_score","seq_recovery"]:
    df[c] = pd.to_numeric(df[c], errors="coerce").round(3)

df.to_csv(OUT_TABLE, index=False)

lines = []
lines.append("# 6MRR RMSD audit v3: deduplicated reference")
lines.append("")
lines.append("## Key correction")
lines.append("The apparent 71-vs-68 C-alpha mismatch can arise when the raw PDB contains duplicate CA atom records, such as alternate conformations. This audit creates a deduplicated chain A reference by keeping one atom per residue/atom-name key, preferring blank altloc, then altloc A, then higher occupancy.")
lines.append("")
lines.append(f"- Raw target PDB: `{target_pdb}`")
lines.append(f"- Raw CA atom records in downloaded target: `{len(raw_all_ca)}`")
lines.append(f"- Unique-residue CA count in downloaded target: `{len(raw_unique_ca)}`")
lines.append(f"- Deduplicated reference PDB: `{OUT_REF_PDB}`")
lines.append(f"- Deduplicated reference CA count: `{len(ref_coords)}`")
lines.append("")
lines.append("## Ranked result")
cols = ["priority_order","short_id","dedup_reference_rmsd_A","mean_plddt","ptm","mpnn_score","seq_recovery","self_consistency_status","reference_mode","target_window_label"]
lines.append(df[cols].to_markdown(index=False))
OUT_AUDIT.write_text("\n".join(lines), encoding="utf-8")

print("Saved:")
print("-", OUT_REF_PDB)
print("-", OUT_TABLE)
print("-", OUT_AUDIT)
display(df)
